import { useState } from 'react'

const SITEMAP_BG = 'data:image/jpeg;base64,'

const BUILDING_POSITIONS = {
  1:  { x: 17, y: 14 }, 2:  { x: 20, y: 72 }, 3:  { x: 33, y: 53 },
  4:  { x: 54, y: 50 }, 5:  { x: 40, y: 65 }, 6:  { x: 54, y: 65 },
  7:  { x: 62, y: 32 }, 8:  { x: 47, y: 32 }, 9:  { x: 73, y: 17 },
  10: { x: 73, y: 52 },
}

const BDATA = {
  1:  { total: 35, occupied: 14, bin: 'TX 24-40001', status: 'Placed in service',   cy: 2026 },
  2:  { total: 30, occupied: 11, bin: 'TX 24-40002', status: 'Placed in service',   cy: 2026 },
  3:  { total: 30, occupied: 4,  bin: 'TX 24-40003', status: 'CO received',         cy: 2026 },
  4:  { total: 39, occupied: 6,  bin: 'TX 24-40004', status: 'CO received',         cy: 2026 },
  5:  { total: 36, occupied: 1,  bin: 'TX 24-40005', status: 'CO received',         cy: 2026 },
  6:  { total: 36, occupied: 3,  bin: 'TX 24-40006', status: 'CO received',         cy: 2026 },
  7:  { total: 36, occupied: 0,  bin: 'TX 24-40007', status: 'Under construction',  cy: 2026 },
  8:  { total: 36, occupied: 8,  bin: 'TX 24-40008', status: 'CO received',         cy: 2026 },
  9:  { total: 30, occupied: 0,  bin: 'TX 24-40009', status: 'Under construction',  cy: 2026 },
  10: { total: 54, occupied: 16, bin: 'TX 24-40010', status: 'Placed in service',   cy: 2026 },
}

const SDOT = {
  'Placed in service': '#639922', 'CO received': '#BA7517',
  'Under construction': '#378ADD', 'Not started': '#8f8e87',
}
const SRING = {
  'Placed in service': '#C0DD97', 'CO received': '#FAC775',
  'Under construction': '#A8D0F5', 'Not started': '#e5e3db',
}

export function SiteMapTab() {
  const [sel, setSel] = useState(null)
  const b = sel ? BDATA[sel] : null
  const occ = b ? Math.round((b.occupied / b.total) * 100) : 0

  return (
    <div>
      <div style={{ fontSize: 12, color: '#6b6a63', marginBottom: 10 }}>
        Click any building marker to see details. Drag to explore the site.
      </div>

      <div style={{ display: 'flex', gap: 12, marginBottom: 12, flexWrap: 'wrap' }}>
        {Object.entries(SDOT).map(([label, color]) => (
          <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
            <div style={{ width: 9, height: 9, borderRadius: '50%', background: color }} />
            <span style={{ fontSize: 11, color: '#6b6a63' }}>{label}</span>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: sel ? '1fr 260px' : '1fr', gap: 14, alignItems: 'start' }}>
        <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', border: '0.5px solid #e5e3db' }}>
          <img src={SITEMAP_BG} alt="Tapestry Centerpoint site map" style={{ width: '100%', display: 'block' }} />
          {Object.entries(BUILDING_POSITIONS).map(([bldg, pos]) => {
            const num = parseInt(bldg)
            const data = BDATA[num]
            const isSel = sel === num
            const dot = SDOT[data.status] || SDOT['Not started']
            const ring = SRING[data.status] || SRING['Not started']
            const pct = Math.round((data.occupied / data.total) * 100)
            return (
              <div key={bldg} onClick={() => setSel(isSel ? null : num)}
                style={{ position: 'absolute', left: pos.x + '%', top: pos.y + '%', transform: 'translate(-50%,-50%)', cursor: 'pointer', zIndex: isSel ? 10 : 1 }}>
                <div style={{
                  width: isSel ? 46 : 36, height: isSel ? 46 : 36, borderRadius: '50%',
                  background: ring, display: 'flex', alignItems: 'center', justifyContent: 'center',
                  boxShadow: isSel ? `0 0 0 3px ${dot}, 0 4px 14px rgba(0,0,0,0.3)` : '0 2px 6px rgba(0,0,0,0.2)',
                  transition: 'all .15s',
                }}>
                  <div style={{
                    width: isSel ? 34 : 26, height: isSel ? 34 : 26, borderRadius: '50%',
                    background: dot, display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column',
                  }}>
                    <span style={{ fontSize: num === 10 ? 9 : 11, fontWeight: 700, color: '#fff', lineHeight: 1 }}>{num}</span>
                    <span style={{ fontSize: 8, color: 'rgba(255,255,255,0.9)', lineHeight: 1.2 }}>{pct}%</span>
                  </div>
                </div>
              </div>
            )
          })}
        </div>

        {sel && b && (
          <div style={{ background: '#fff', border: '0.5px solid #e5e3db', borderRadius: 12, padding: '1rem', position: 'sticky', top: 0 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
              <div>
                <div style={{ fontSize: 16, fontWeight: 600, color: '#1a1a18' }}>Building {sel}</div>
                <div style={{ fontSize: 11, color: '#8f8e87', fontFamily: 'monospace', marginTop: 1 }}>{b.bin}</div>
              </div>
              <button onClick={() => setSel(null)} style={{ background: 'none', border: 'none', fontSize: 18, color: '#8f8e87', cursor: 'pointer', lineHeight: 1 }}>×</button>
            </div>

            <div style={{ display: 'inline-flex', alignItems: 'center', gap: 6, padding: '3px 10px', borderRadius: 100, background: SRING[b.status], marginBottom: 14 }}>
              <div style={{ width: 7, height: 7, borderRadius: '50%', background: SDOT[b.status] }} />
              <span style={{ fontSize: 11, fontWeight: 500, color: '#1a1a18' }}>{b.status}</span>
            </div>

            <div style={{ marginBottom: 14 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: '#6b6a63', marginBottom: 4 }}>
                <span>Occupancy</span>
                <span style={{ fontWeight: 500, color: '#1a1a18' }}>{b.occupied} / {b.total} ({occ}%)</span>
              </div>
              <div style={{ height: 8, background: '#e5e3db', borderRadius: 4, overflow: 'hidden' }}>
                <div style={{ width: occ + '%', height: '100%', borderRadius: 4, background: occ >= 90 ? '#639922' : occ >= 50 ? '#378ADD' : occ >= 20 ? '#BA7517' : '#E24B4A' }} />
              </div>
            </div>

            {[
              ['Total units', b.total], ['Occupied', b.occupied], ['Vacant', b.total - b.occupied],
              ['First credit year', b.cy], ['BIN', b.bin],
            ].map(([label, val]) => (
              <div key={label} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, padding: '6px 0', borderBottom: '0.5px solid #f0ede6' }}>
                <span style={{ color: '#6b6a63' }}>{label}</span>
                <span style={{ fontWeight: 500, color: '#1a1a18' }}>{val}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}
